import React from "react";
import "./About.css";

export default function About() {
  const mainImg =
    "https://static.vecteezy.com/system/resources/thumbnails/019/050/491/small/a-girl-sitting-and-writing-a-diet-plan-weight-loss-concept-eat-food-that-is-good-for-the-body-such-as-fruits-and-vegetables-free-photo.jpg";

  const benefits = [
    {
      title: "Personalized Diet Plans",
      desc: "Your nutrition plan is customized based on your goals, lifestyle, and food habits for the best long-term results.",
      img: "https://images.pexels.com/photos/7441763/pexels-photo-7441763.jpeg?auto=compress&cs=tinysrgb&w=600",
    },
    {
      title: "Expert Guidance",
      desc: "Our certified experts help you stay accountable, motivated, and informed throughout your health journey.",
      img: "https://images.pexels.com/photos/8064270/pexels-photo-8064270.jpeg?auto=compress&cs=tinysrgb&w=600",
    },
    {
      title: "Science-Based Nutrition",
      desc: "Everything we recommend is backed by proven nutrition science and research for maximum effectiveness.",
      img: "https://images.pexels.com/photos/7578809/pexels-photo-7578809.jpeg?auto=compress&cs=tinysrgb&w=600",
    },
    {
      title: "Healthy Lifestyle Habits",
      desc: "We help you build simple, sustainable healthy habits that last a lifetime — no strict diets or restrictions.",
      img: "https://images.pexels.com/photos/8449258/pexels-photo-8449258.jpeg?auto=compress&cs=tinysrgb&w=600",
    },
  ];

  return (
    <div className="about-page">
      <div className="about-card">
        {/* LEFT SIDE TEXT */}
        <div className="about-content">
          <span className="tag">ABOUT US</span>

          <h1>Your Health, Our Priority</h1>
          <p>
            We guide individuals towards better health through personalized meal
            plans, science-backed nutrition, and practical lifestyle habits.
            Whether you're aiming for weight loss, improved energy, or a better
            relationship with food — we help you every step of the way.
          </p>

          <div className="about-buttons">
            <button className="btn-primary">Learn More</button>
            <button className="btn-secondary">Why Choose Us?</button>
          </div>
        </div>

        {/* RIGHT SIDE IMAGE */}
        <div className="about-image-box">
          <img src={mainImg} alt="about-nutrition" />
        </div>
      </div>

      {/* BENEFITS SECTION */}
      <h2 className="benefits-title">Why Choose Our Platform?</h2>

      <div className="benefits-row">
        {benefits.map((b, i) => (
          <div className="benefit-card" key={i}>
            <img className="benefit-img" src={b.img} alt={b.title} />
            <h3>{b.title}</h3>
            <p>{b.desc}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
